import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../supabaseClient';

const STATUS_COLORS = {
  concept: '#8b5cf6', script: '#3b82f6', production: '#f59e0b',
  edit: '#f97316', review: '#ec4899', published: '#22c55e',
};

const STATUS_LABELS = {
  concept: 'Concept', script: 'Script', production: 'Production',
  edit: 'Edit', review: 'Review', published: 'Published',
};

export default function Calendar() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [viewDate, setViewDate] = useState(new Date());
  const [viewMode, setViewMode] = useState('month'); // 'month' or 'quarter'
  const [filterStatus, setFilterStatus] = useState('all');
  const scrollRef = useRef(null);

  useEffect(() => {
    const timeout = setTimeout(() => setLoading(false), 5000);
    fetchProjects().finally(() => clearTimeout(timeout));
    return () => clearTimeout(timeout);
  }, []);

  async function fetchProjects() {
    try {
      const { data, error } = await supabase
        .from('projects')
        .select('*')
        .order('start_date', { ascending: true });
      if (error) throw error;
      setProjects(data || []);
    } catch (err) {
      console.error('Error:', err);
      setProjects([]);
    } finally {
      setLoading(false);
    }
  }

  // Calculate date range for the view
  function getDateRange() {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();

    if (viewMode === 'month') {
      const start = new Date(year, month, 1);
      const end = new Date(year, month + 1, 0);
      return { start, end, days: end.getDate() };
    } else {
      // Quarter view: 3 months
      const qStart = Math.floor(month / 3) * 3;
      const start = new Date(year, qStart, 1);
      const end = new Date(year, qStart + 3, 0);
      const days = Math.ceil((end - start) / (1000 * 60 * 60 * 24)) + 1;
      return { start, end, days };
    }
  }

  const { start: rangeStart, end: rangeEnd, days: totalDays } = getDateRange();

  function navigateView(direction) {
    const d = new Date(viewDate);
    if (viewMode === 'month') {
      d.setMonth(d.getMonth() + direction);
    } else {
      d.setMonth(d.getMonth() + (direction * 3));
    }
    setViewDate(d);
  }

  // Generate day columns
  function getDays() {
    const days = [];
    const d = new Date(rangeStart);
    while (d <= rangeEnd) {
      days.push(new Date(d));
      d.setDate(d.getDate() + 1);
    }
    return days;
  }

  const allDays = getDays();

  // Calculate bar position for a project
  function getBarStyle(project) {
    const pStart = new Date(project.start_date);
    const pEnd = new Date(project.deadline);

    // Clamp to view range
    const barStart = pStart < rangeStart ? rangeStart : pStart;
    const barEnd = pEnd > rangeEnd ? rangeEnd : pEnd;

    if (barStart > rangeEnd || barEnd < rangeStart) return null;

    const startOffset = Math.max(0, (barStart - rangeStart) / (1000 * 60 * 60 * 24));
    const duration = Math.max(1, (barEnd - barStart) / (1000 * 60 * 60 * 24) + 1);
    const leftPercent = (startOffset / totalDays) * 100;
    const widthPercent = (duration / totalDays) * 100;

    return {
      left: `${leftPercent}%`,
      width: `${widthPercent}%`,
    };
  }

  const filtered = projects.filter(p => {
    if (filterStatus !== 'all' && p.status !== filterStatus) return false;
    // Only show projects that overlap with the view range
    const pStart = new Date(p.start_date);
    const pEnd = new Date(p.deadline);
    return pStart <= rangeEnd && pEnd >= rangeStart;
  });

  const viewTitle = viewMode === 'month'
    ? viewDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })
    : `Q${Math.floor(viewDate.getMonth() / 3) + 1} ${viewDate.getFullYear()}`;

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.topBar}>
        <div>
          <h1 style={styles.pageTitle}>Calendar</h1>
          <p style={styles.pageSubtitle}>
            {filtered.length} projects in view
          </p>
        </div>
      </div>

      {/* Controls */}
      <div style={styles.controlsRow}>
        <div style={styles.navControls}>
          <button onClick={() => navigateView(-1)} style={styles.navBtn}>←</button>
          <span style={styles.viewTitle}>{viewTitle}</span>
          <button onClick={() => navigateView(1)} style={styles.navBtn}>→</button>
          <button
            onClick={() => setViewDate(new Date())}
            style={styles.todayBtn}
          >Today</button>
        </div>
        <div style={styles.viewToggle}>
          <button
            onClick={() => setViewMode('month')}
            style={{
              ...styles.viewBtn,
              ...(viewMode === 'month' ? styles.viewBtnActive : {}),
            }}
          >Month</button>
          <button
            onClick={() => setViewMode('quarter')}
            style={{
              ...styles.viewBtn,
              ...(viewMode === 'quarter' ? styles.viewBtnActive : {}),
            }}
          >Quarter</button>
        </div>
      </div>

      {/* Status Filter */}
      <div style={styles.filterRow}>
        <button
          onClick={() => setFilterStatus('all')}
          style={{
            ...styles.filterBtn,
            ...(filterStatus === 'all' ? styles.filterBtnActive : {}),
          }}
        >All</button>
        {Object.keys(STATUS_COLORS).map(s => (
          <button
            key={s}
            onClick={() => setFilterStatus(s)}
            style={{
              ...styles.filterBtn,
              ...(filterStatus === s ? {
                background: `${STATUS_COLORS[s]}20`,
                color: STATUS_COLORS[s],
                borderColor: `${STATUS_COLORS[s]}40`,
              } : {}),
            }}
          >{STATUS_LABELS[s]}</button>
        ))}
      </div>

      {/* Gantt Chart */}
      <div style={styles.chartContainer} ref={scrollRef}>
        {/* Day Headers */}
        <div style={styles.dayHeaders}>
          <div style={styles.projectNameCol}>Project</div>
          <div style={styles.daysArea}>
            {allDays.map((day, i) => {
              const isToday = day.toDateString() === new Date().toDateString();
              const isWeekend = day.getDay() === 0 || day.getDay() === 6;
              const isFirstOfMonth = day.getDate() === 1;
              return (
                <div
                  key={i}
                  style={{
                    ...styles.dayHeader,
                    width: `${100 / totalDays}%`,
                    color: isToday ? '#6366f1' : isWeekend ? 'rgba(255,255,255,0.2)' : 'rgba(255,255,255,0.35)',
                    fontWeight: isToday ? 700 : 400,
                    borderLeft: isFirstOfMonth && viewMode === 'quarter' ? '1px solid rgba(255,255,255,0.1)' : 'none',
                  }}
                >
                  {viewMode === 'month' ? (
                    <>
                      <span style={{ fontSize: '10px' }}>
                        {day.toLocaleDateString('en-US', { weekday: 'narrow' })}
                      </span>
                      <span>{day.getDate()}</span>
                    </>
                  ) : (
                    day.getDate() === 1 || day.getDate() === 15 ? (
                      <span>{day.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                    ) : null
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Project Rows */}
        {loading ? (
          <p style={{ padding: '20px', color: 'rgba(255,255,255,0.35)' }}>Loading...</p>
        ) : filtered.length === 0 ? (
          <p style={{ padding: '20px', color: 'rgba(255,255,255,0.35)' }}>No projects in this date range.</p>
        ) : (
          filtered.map(project => {
            const barStyle = getBarStyle(project);
            return (
              <div key={project.id} style={styles.chartRow}>
                <div style={styles.projectNameCol}>
                  <div style={styles.chartProjectName}>{project.name}</div>
                  <div style={styles.chartProjectType}>
                    {project.type.replace('_', ' ')}
                    {project.channel && ` · ${project.channel}`}
                  </div>
                </div>
                <div style={styles.daysArea}>
                  {/* Grid lines */}
                  {allDays.map((day, i) => {
                    const isToday = day.toDateString() === new Date().toDateString();
                    const isWeekend = day.getDay() === 0 || day.getDay() === 6;
                    return (
                      <div
                        key={i}
                        style={{
                          ...styles.gridCell,
                          width: `${100 / totalDays}%`,
                          background: isToday
                            ? 'rgba(99,102,241,0.08)'
                            : isWeekend
                              ? 'rgba(255,255,255,0.01)'
                              : 'transparent',
                        }}
                      />
                    );
                  })}
                  {/* Bar */}
                  {barStyle && (
                    <div
                      style={{
                        ...styles.bar,
                        ...barStyle,
                        background: `linear-gradient(135deg, ${STATUS_COLORS[project.status]}, ${STATUS_COLORS[project.status]}99)`,
                      }}
                      title={`${project.name}: ${new Date(project.start_date).toLocaleDateString()} - ${new Date(project.deadline).toLocaleDateString()}`}
                    >
                      <span style={styles.barLabel}>{project.name}</span>
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}

        {/* Today line */}
        {(() => {
          const today = new Date();
          if (today >= rangeStart && today <= rangeEnd) {
            const offset = (today - rangeStart) / (1000 * 60 * 60 * 24);
            const leftPercent = (offset / totalDays) * 100;
            return (
              <div style={{
                position: 'absolute',
                left: `calc(200px + ${leftPercent}% * (100% - 200px) / 100%)`,
                top: 0,
                bottom: 0,
                width: '2px',
                background: '#6366f1',
                zIndex: 10,
                pointerEvents: 'none',
                opacity: 0.6,
              }} />
            );
          }
          return null;
        })()}
      </div>

      {/* Legend */}
      <div style={styles.legend}>
        {Object.entries(STATUS_COLORS).map(([status, color]) => (
          <div key={status} style={styles.legendItem}>
            <div style={{ ...styles.legendDot, background: color }} />
            <span>{STATUS_LABELS[status]}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

